import axios from "axios";

import {useState}
from "react";

function CourseForm(){

const [skills,setSkills]
= useState("");

const [goal,setGoal]
= useState("");

const [data,setData]
= useState(null);

const [loading,setLoading]
= useState(false);

async function analyze(){

setLoading(true);

const res =
await axios.post(

"http://localhost:5001/api/recommend",

{

skills,

goal

}

);

setData(res.data);

setLoading(false);

}

return(

<div>

<input

placeholder="Your skills"

value={skills}

onChange={e=>
setSkills(
e.target.value
)}

 />

<input

placeholder="Career goal"

value={goal}

onChange={e=>
setGoal(
e.target.value
)}

 />

<button
onClick={analyze}>

{loading ?
"Generating..."
:
"Generate Roadmap"
}

</button>

{data && (

<div>

<h2>
Learning Path
</h2>

{data.roadmap.map(
(step,i)=>(

<div
className="stepCard"
key={i}>

<h3>

Step {step.step}

</h3>

<h2>

{step.title}

</h2>

<p>

{step.description}

</p>

<p>

⏱ {step.time}

</p>

<p>

📈 {step.level}

</p>

<h4>

Topics:

</h4>

<ul>

{step.topics.map(
(t,i)=>(

<li key={i}>
{t}
</li>

))}

</ul>

<h3>
Courses
</h3>

<div
className="courseGrid">

{step.courses.map(
(course,i)=>(

<div
className="courseCard"
key={i}>

<img
src={course.image}
alt=""
/>

<h4>

{course.name}

</h4>

<p>

Platform:
{course.platform}

</p>

<p>

⭐ {course.rating}

</p>

<p>

💰 {course.price}

</p>

<p>

⏱ {course.duration}

</p>

<p>

👨‍🎓 {course.students}

</p>

<a
href={course.link}
target="_blank">

View Course

</a>

</div>

))}

</div>

</div>

))

}

</div>

)}

</div>

);

}

export default CourseForm;
